/**
 * Cover panel — Page 1 of the peptide report.
 *
 * Contents:
 * - PVL title + peptide ID
 * - Sequence in monospace
 * - Classification pills (Helix / FF-Helix / SSW / FF-SSW)
 * - Dataset name, timestamp, PVL version
 * - Zenodo DOI placeholder
 * - Embedded permalink (text + QR code placeholder)
 * - "Generated by Peptide Visual Lab" footer
 */

import type { jsPDF } from "jspdf";
import type { Peptide } from "@/types/peptide";
import type { ReportData, ReportPanel, RenderContext } from "../peptideReport";
import { REPORT_COLORS, drawParagraph } from "../peptideReport";

const MARGIN = 20;

function drawCoverContent(
  doc: jsPDF,
  peptide: Peptide,
  data: ReportData,
  ctx: RenderContext,
): void {
  let y = ctx.contentTop + 5;

  // ── PVL Logo text ──────────────────────────────────────────────
  doc.setFontSize(28);
  doc.setFont("helvetica", "bold");
  doc.setTextColor(REPORT_COLORS.sectionHeading);
  doc.text("Peptide Visual Lab", MARGIN, y);
  y += 10;

  doc.setFontSize(12);
  doc.setFont("helvetica", "normal");
  doc.setTextColor(REPORT_COLORS.mutedText);
  doc.text("Single-Peptide Analysis Report", MARGIN, y);
  y += 16;

  // ── Divider ────────────────────────────────────────────────────
  doc.setDrawColor(REPORT_COLORS.sectionHeading);
  doc.setLineWidth(0.8);
  doc.line(MARGIN, y, ctx.pageWidth - MARGIN, y);
  y += 12;

  // ── Peptide identity ───────────────────────────────────────────
  doc.setFontSize(18);
  doc.setFont("helvetica", "bold");
  doc.setTextColor(REPORT_COLORS.bodyText);
  const title = peptide.name
    ? `${peptide.id} — ${peptide.name}`
    : peptide.id;
  doc.text(title, MARGIN, y);
  y += 8;

  if (peptide.species) {
    doc.setFontSize(10);
    doc.setFont("helvetica", "italic");
    doc.setTextColor(REPORT_COLORS.mutedText);
    doc.text(peptide.species, MARGIN, y);
    y += 8;
  }

  // ── Sequence ───────────────────────────────────────────────────
  y += 4;
  doc.setFontSize(9);
  doc.setFont("courier", "normal");
  doc.setTextColor(REPORT_COLORS.bodyText);

  // Wrap sequence at ~60 chars per line
  const seq = peptide.sequence;
  const chunkSize = 60;
  for (let i = 0; i < seq.length; i += chunkSize) {
    doc.text(seq.slice(i, i + chunkSize), MARGIN, y);
    y += 5;
  }
  y += 4;

  doc.setFont("helvetica", "normal");
  doc.setFontSize(9);
  doc.setTextColor(REPORT_COLORS.mutedText);
  doc.text(`${peptide.length ?? seq.length} amino acids`, MARGIN, y);
  y += 12;

  // ── Classification pills ───────────────────────────────────────
  const pills: Array<{ label: string; color: string; active: boolean }> = [
    {
      label: "Helix",
      color: REPORT_COLORS.helix,
      active: (peptide.s4predHelixPrediction ?? 0) === 1,
    },
    {
      label: "FF-Helix",
      color: REPORT_COLORS.ffHelix,
      active: peptide.ffHelixFlag === 1,
    },
    {
      label: "SSW",
      color: REPORT_COLORS.ssw,
      active:
        peptide.sswPrediction === 1 ||
        (peptide.s4predSswPrediction ?? 0) === 1,
    },
    {
      label: "FF-SSW",
      color: REPORT_COLORS.ffSsw,
      active: peptide.ffSswFlag === 1,
    },
  ];

  doc.setFontSize(8);
  let pillX = MARGIN;
  for (const pill of pills) {
    const w = doc.getTextWidth(pill.label) + 8;
    const h = 7;

    if (pill.active) {
      doc.setFillColor(pill.color);
      doc.roundedRect(pillX, y - 5, w, h, 2, 2, "F");
      doc.setTextColor("#ffffff");
    } else {
      doc.setDrawColor(REPORT_COLORS.border);
      doc.roundedRect(pillX, y - 5, w, h, 2, 2, "S");
      doc.setTextColor(REPORT_COLORS.mutedText);
    }

    doc.setFont("helvetica", "bold");
    doc.text(pill.label, pillX + 4, y);
    pillX += w + 4;
  }
  y += 16;

  // ── Report metadata ────────────────────────────────────────────
  doc.setDrawColor(REPORT_COLORS.border);
  doc.setLineWidth(0.3);
  doc.line(MARGIN, y, ctx.pageWidth - MARGIN, y);
  y += 8;

  const metaRows: Array<[string, string]> = [];
  if (data.datasetName) metaRows.push(["Dataset", data.datasetName]);
  metaRows.push(["PVL Version", `v${data.version}`]);
  if (data.buildSha) metaRows.push(["Build", data.buildSha.slice(0, 12)]);
  metaRows.push([
    "Generated",
    new Date().toLocaleString("en-US", {
      dateStyle: "long",
      timeStyle: "short",
    }),
  ]);
  metaRows.push(["DOI", "Pending — Zenodo submission in progress"]);

  doc.setFontSize(9);
  for (const [key, value] of metaRows) {
    doc.setFont("helvetica", "bold");
    doc.setTextColor(REPORT_COLORS.bodyText);
    doc.text(`${key}:`, MARGIN, y);
    doc.setFont("helvetica", "normal");
    doc.setTextColor(REPORT_COLORS.mutedText);
    doc.text(value, MARGIN + 35, y);
    y += 6;
  }
  y += 8;

  // ── Permalink ──────────────────────────────────────────────────
  if (data.permalink) {
    doc.setFontSize(8);
    doc.setFont("helvetica", "bold");
    doc.setTextColor(REPORT_COLORS.sectionHeading);
    doc.text("Analysis Permalink:", MARGIN, y);
    y += 5;
    doc.setFont("courier", "normal");
    doc.setFontSize(7);
    doc.setTextColor(REPORT_COLORS.mutedText);
    // Wrap long URLs
    const lines = doc.splitTextToSize(data.permalink, ctx.contentWidth);
    for (const line of lines) {
      doc.text(line, MARGIN, y);
      y += 4;
    }
    y += 4;

    // QR code placeholder (requires qrcode-generator — deferred to wiring phase)
    doc.setFontSize(7);
    doc.setFont("helvetica", "italic");
    doc.setTextColor(REPORT_COLORS.mutedText);
    doc.text("[QR code — generated at render time when qrcode-generator is installed]", MARGIN, y);
  }
}

export const coverPanel: ReportPanel = {
  id: "cover",
  title: "Peptide Analysis Report",
  render: drawCoverContent,
};
